#[repr(C)]
pub struct NativeMemoryFixturePacket {
    tag: u32,
    count: u32,
    checksum: u32,
    reserved: u32,
}

#[no_mangle]
pub extern "C" fn native_memory_fixture_sum(
    ptr: *const NativeMemoryFixturePacket,
    count: usize,
) -> u32 {
    if ptr.is_null() {
        return 0;
    }

    let packets = unsafe { std::slice::from_raw_parts(ptr, count) };
    let mut total = 0u32;
    for packet in packets {
        total = total
            .wrapping_add(packet.tag)
            .wrapping_add(packet.count)
            .wrapping_add(packet.checksum)
            .wrapping_add(packet.reserved);
    }
    total
}
